module RefModule(  
    input clk,  
    input reset,  
    input taken,  
    output reg prediction  
);  
    reg [0:0] unused_counter;  

    always @(posedge clk or posedge reset) begin  
        if (reset)  
            unused_counter <= 1'b0;  
        else begin  
            if (taken)  
                unused_counter <= (unused_counter == 1'b1) ? 1'b1 : unused_counter + 1'b1;  
            else  
                unused_counter <= (unused_counter == 1'b0) ? 1'b0 : unused_counter - 1'b1;  
        end  
    end  

    always @(*) begin  
        prediction = unused_counter;  
    end  
endmodule
